mapper.select:
SELECT id, name, code, description, sort_order, status, created_at as createdAt, updated_at as updatedAt FROM notice_category WHERE is_deleted = 0
AND name LIKE CONCAT('%', #{request.name}, '%')
AND code LIKE CONCAT('%', #{request.code}, '%')
AND status = #{request.status}
ORDER BY sort_order ASC, created_at DESC LIMIT #{size} OFFSET #{offset}
